const textArea = document.querySelector('#tweetBox');
const counter = document.querySelector('#charCount');

// Fires instantly on every single keystroke, paste, or delete
textArea.addEventListener('input', (e) => {
  const currentLength = e.target.value.length;
  counter.innerText = `${currentLength}/280`;
});

const select = document.querySelector('#countryDropdown');
// Fires only when the user selects a new option and the dropdown closes
select.addEventListener('change', (e) => {
  console.log('You finalized your choice:', e.target.value);
});

